package com.hospital.management.validation;import com.hospital.management.model.*;import java.math.*;import java.util.*;/** Validates bill forms without accepting client-calculated totals. */public class BillValidator{private static final Set<String>TYPES=Set.of("CONSULTATION","ROOM","MEDICINE","LAB_TEST","PROCEDURE","OTHER");private static final BigDecimal MAX=new BigDecimal("999999999999.99");public ValidationResult validate(BillForm f){ValidationResult v=new ValidationResult();if(f==null){v.addError("form","Bill is required");return v;}if(f.getPatientId()==null||f.getPatientId()<=0)v.addError("patientId","Select a patient");if(f.getAppointmentId()!=null&&f.getAppointmentId()<=0)v.addError("appointmentId","Invalid appointment");money(f.getTaxAmount(),"taxAmount",v,true);money(f.getDiscountAmount(),"discountAmount",v,true);List<BillItemForm>x=f.getItems();if(x==null||x.isEmpty())v.addError("items","At least one bill item is required");else if(x.size()>50)v.addError("items","A maximum of 50 items is allowed");if(x!=null)for(int i=0;i<x.size();i++)item(x.get(i),i,v);return v;}public ValidationResult validate(BillForm f,BigDecimal subtotal){ValidationResult v=validate(f);BigDecimal d=parse(f==null?null:f.getDiscountAmount());if(d!=null&&subtotal!=null&&d.compareTo(subtotal)>0)v.addError("discountAmount","Discount cannot exceed subtotal");return v;}private void item(BillItemForm x,int i,ValidationResult v){String p="items["+i+"]";if(x==null){v.addError(p,"Item is required");return;}if(x.getItemType()==null||!TYPES.contains(x.getItemType().toUpperCase()))v.addError(p+".itemType","Select a valid type");String d=x.getDescription()==null?"":x.getDescription().trim();if(d.length()<2||d.length()>500)v.addError(p+".description","Description must be 2 to 500 characters");BigDecimal q=money(x.getQuantity(),p+".quantity",v,false);if(q!=null&&q.signum()<=0)v.addError(p+".quantity","Quantity must be greater than zero");money(x.getUnitPrice(),p+".unitPrice",v,true);}private BigDecimal money(String s,String f,ValidationResult v,boolean zero){if(s==null||s.isBlank())return BigDecimal.ZERO;BigDecimal n=parse(s);if(n==null){v.addError(f,"Enter a valid amount");return null;}if(n.scale()>2)v.addError(f,"Use no more than two decimal places");if((zero?n.signum()<0:n.signum()<=0)||n.compareTo(MAX)>0)v.addError(f,"Amount is outside the allowed range");return n;}private BigDecimal parse(String s){try{return s==null||s.isBlank()?BigDecimal.ZERO:new BigDecimal(s.trim());}catch(Exception e){return null;}}}
